31	export type Step = QuoteStep | ClaimStep;
32	
33	export interface Scenario {
34	  customer: Customer;
35	  steps: Step[];
36	}
37	
38	export interface QuoteResult {
39	  premium: number;
40	}
41	
42	export interface ClaimResult {
43	  payout: number;
44	  remainingCap: number;
45	}
46	
47	export type StepResult = QuoteResult | ClaimResult;
48	
49	export interface ScenarioResult {
50	  results: StepResult[];
51	}
52	
53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
64	
65	const quote = ({ items }: QuoteStep): QuoteResult => ({
66	  premium: items.reduce(
67	    (sum, item) => sum + basePremiumFor(item),
68	    PROCESSING_FEE,
69	  ),
70	});
71	
72	export const runScenario = (scenario: Scenario): ScenarioResult => ({
73	  results: scenario.steps.map((step) =>
74	    step.op === "quote" ? quote(step) : { payout: 0, remainingCap: 0 },
75	  ),
76	});
